// src/App.jsx (или файл с роутами)

import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import ScrollToTop from '../../ScrollToTop/ScrollToTop';
import Layout from './components/Layout'; // Импорт Layout

// Импорт всех страниц
import MainPage from './pages/MainPage';
import CategoriesPage from './pages/CategoriesPage';
import ProductsPage from './pages/ProductsPage';
import ProductDetailsPage from './pages/ProductDetailsPage';
import CartPage from './pages/CartPage';
import NotFoundPage from './pages/NotFoundPage'; // Предполагаем, что есть 404

const App = () => {
  return (
    <BrowserRouter>
      {/* Оборачиваем все маршруты в Layout */}
      <Layout>
        <Routes>
          {/* Публичные маршруты */}
          <Route path="/" element={<MainPage />} />
          <Route path="/categories" element={<CategoriesPage />} />
          <Route path="/products" element={<ProductsPage />} />
          {/* Маршрут для товаров по категории */}
          <Route path="/categories/:id" element={<ProductsPage />} /> 
          {/* Маршрут для деталей продукта */}
          <Route path="/products/:id" element={<ProductDetailsPage />} />
          <Route path="/cart" element={<CartPage />} />

          {/* Страница 404 */}
          <Route path="*" element={<NotFoundPage />} />
        </Routes>
      </Layout>
    </BrowserRouter>
  );
};

export default App;
